import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import '../../styles/header.css';
import logo from '../../assets/logo.png';

const Header = () => {
  return (
    <header className={styles.header}>
      <div className={styles.container}>
        <nav className={styles.navbar}>
          {/* Logo */}
          <a href="/" className={styles.logo}>
            <img src="/logo.png" alt="Channel4Me Logo" />
          </a>

          {/* Navigation Menu */}
          <ul className={styles.navMenu}>
            <li><a href="/" className={`${styles.navLink} ${styles.active}`}>Home</a></li>
            <li><a href="/features" className={styles.navLink}>Features</a></li>
            <li><a href="/doctors" className={styles.navLink}>Doctors</a></li>
            <li><a href="/specialties" className={styles.navLink}>Specialties</a></li>
            <li><a href="/about" className={styles.navLink}>About</a></li>
          </ul>

          {/* Auth Buttons */}
          <div className={styles.navButtons}>
            <a href="/login" className={`${styles.btn} ${styles.btnOutline}`}>
              Log In
            </a>
            <a href="/register" className={`${styles.btn} ${styles.btnPrimary}`}>
              Sign Up Free
            </a>
          </div>
        </nav>
      </div>
    </header>
  );
};

export default Header;
